1230	       * `linked_view`: linked elements use the source model's stored view
1231	       *   definitions (rendered via the source's own VV / categories).
1232	       */
1233	      visibilityMode?: 'host_view' | 'linked_view';
1234	      hidden?: boolean;
1235	      pinned?: boolean;
1236	    }
1237	  | {
1238	      /**
1239	       * FED-04 — DXF underlay parsed from a customer's 2D site plan.
1240	       *
1241	       * The host materialises this element after `parse_dxf_to_linework`
1242	       * runs server-side; the plan canvas renders `linework[]` as
1243	       * desaturated grey strokes beneath authored geometry on `levelId`.
1244	       * `scaleFactor` carries the unit conversion the parser inferred from
1245	       * the DXF `$INSUNITS` header.
1246	       */
1247	      kind: 'link_dxf';
1248	      id: string;
1249	      name?: string;
1250	      levelId: string;
1251	      originMm: XY;
1252	      rotationDeg?: number;
1253	      scaleFactor?: number;
1254	      linework: DxfLineworkPrim[];
1255	      pinned?: boolean;
1256	    }
1257	  | {
1258	      /**
1259	       * KRN-15 — project-level swept solid.
1260	       *
1261	       * Extrudes a closed 2D `profileMm` along an open or closed
1262	       * `pathMm` polyline. Used for fascia, gutters, mullion bodies,
1263	       * picture-frame outlines around recessed loggias, and any
1264	       * linear architectural feature with a constant cross-section.
1265	       */
1266	      kind: 'sweep';
1267	      id: string;
1268	      name?: string;
1269	      levelId: string;
1270	      pathMm: { xMm: number; yMm: number; zMm?: number }[];
1271	      profileMm: { uMm: number; vMm: number }[];
1272	      profilePlane: 'normal_to_path_start' | 'work_plane';
1273	      materialKey?: string | null;
1274	      worksetId?: string | null;
1275	      pinned?: boolean;
1276	      phaseCreated?: string | null;
1277	      phaseDemolished?: string | null;
1278	    }
1279	  | {
1280	      /**
1281	       * KRN-14 — dormer load-bearing slice.
1282	       *
1283	       * Cuts the host roof and adds dormer walls + roof at the
1284	       * `positionOnRoof` (local roof coords; alongRidgeMm is along
1285	       * the ridge axis, acrossRidgeMm is the perpendicular distance
1286	       * from ridge midpoint).
1287	       */
1288	      kind: 'dormer';
1289	      id: string;
1290	      name?: string;
1291	      hostRoofId: string;
1292	      positionOnRoof: { alongRidgeMm: number; acrossRidgeMm: number };
1293	      widthMm: number;
1294	      wallHeightMm: number;
1295	      depthMm: number;
1296	      dormerRoofKind: 'flat' | 'shed' | 'gable' | 'hipped';
1297	      dormerRoofPitchDeg?: number;
1298	      ridgeHeightMm?: number;
1299	      wallMaterialKey?: string | null;
1300	      roofMaterialKey?: string | null;
1301	      hasFloorOpening?: boolean;
1302	      pinned?: boolean;
1303	      phaseCreated?: string | null;
1304	      phaseDemolished?: string | null;
1305	    }
1306	  | {
1307	      /**
1308	       * KRN-08 — `area` element kind for legal/permit area calculations.
1309	       *
1310	       * Distinct from `room`: areas may include exterior porches and exclude
1311	       * interior shafts based on `ruleSet`. Authored via SKT-01 sketch session.
1312	       * `computedAreaSqMm` is recomputed by the engine after every command apply.
1313	       */
1314	      kind: 'area';
1315	      id: string;
1316	      name: string;
1317	      levelId: string;
1318	      boundaryMm: XY[];
1319	      ruleSet: 'gross' | 'net' | 'no_rules';
1320	      computedAreaSqMm?: number;
1321	      pinned?: boolean;
1322	      phaseCreated?: string | null;
1323	      phaseDemolished?: string | null;
1324	    }
1325	  | {
1326	      /**
1327	       * KRN-10 — view-local 2D filled region that occludes underlying linework.
1328	       * Renders on plan / section / elevation as an opaque polygon above element
1329	       * linework but below text/dimension annotations. Not visible in 3D.
1330	       */
1331	      kind: 'masking_region';
1332	      id: string;
1333	      hostViewId: string;
