1340	       * evaluates constraints after each command apply and rejects the
1341	       * bundle when any `error`-severity constraint is violated. The most
1342	       * common case is `equal_distance` with a `lockedValueMm` captured
1343	       * from the padlock UI on a temp-dimension.
1344	       */
1345	      kind: 'constraint';
1346	      id: string;
